import React, { useEffect, useMemo, useState } from "react";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Tooltip,
  Legend,
} from "chart.js";
import { Line } from "react-chartjs-2";
import PageHeader from "../components/PageHeader";
import { createExpense, fetchCategories, fetchExpenses } from "../api/expenses";
import { useNavigate } from "react-router-dom";
import { formatCurrency } from "../utils/format";

ChartJS.register(CategoryScale, LinearScale, PointElement, LineElement, Tooltip, Legend);

const AddExpense = () => {
  const navigate = useNavigate();
  const [categories, setCategories] = useState([]);
  const [expenses, setExpenses] = useState([]);
  const [form, setForm] = useState({
    merchant: "",
    amount: "",
    expense_date: "",
    category: "",
    payment_method: "credit_card",
    description: "",
    receipt_file: null,
  });
  const [status, setStatus] = useState({ loading: false, error: "", success: "" });

  useEffect(() => {
    fetchCategories()
      .then(setCategories)
      .catch(() => setCategories([]));
  }, []);

  useEffect(() => {
    fetchExpenses()
      .then(setExpenses)
      .catch(() => setExpenses([]));
  }, []);

  const monthlyTrend = useMemo(() => {
    const now = new Date();
    const months = [];
    for (let i = 5; i >= 0; i -= 1) {
      const date = new Date(now.getFullYear(), now.getMonth() - i, 1);
      const key = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, "0")}`;
      const label = date.toLocaleDateString("en-US", { month: "short" });
      months.push({ key, label, total: 0 });
    }

    expenses.forEach((expense) => {
      const rawDate = expense.expense_date || expense.date;
      const parsed = rawDate ? new Date(rawDate) : null;
      if (!parsed || Number.isNaN(parsed.getTime())) {
        return;
      }
      const key = `${parsed.getFullYear()}-${String(parsed.getMonth() + 1).padStart(2, "0")}`;
      const month = months.find((item) => item.key === key);
      if (month) {
        month.total += Number(expense.amount || 0);
      }
    });

    const fallback = [8200, 13400, 9200, 15600, 12100, 14800];
    const data = months.some((m) => m.total > 0)
      ? months.map((m) => m.total)
      : fallback;

    return {
      labels: months.map((m) => m.label),
      data,
      latest: data[data.length - 1] || 0,
    };
  }, [expenses]);

  const handleChange = (event) => {
    const { name, value } = event.target;
    setForm((prev) => ({ ...prev, [name]: value }));
  };

  const handleFileChange = (event) => {
    setForm((prev) => ({ ...prev, receipt_file: event.target.files[0] }));
  };

  const handleSubmit = async (event) => {
    event.preventDefault();
    setStatus({ loading: true, error: "", success: "" });
    try {
      const payload = new FormData();
      payload.append("merchant", form.merchant);
      payload.append("amount", form.amount);
      payload.append("expense_date", form.expense_date);
      payload.append("category", form.category);
      payload.append("payment_method", form.payment_method);
      payload.append("description", form.description);
      if (form.receipt_file) {
        payload.append("receipt_file", form.receipt_file);
      }
      await createExpense(payload);
      setStatus({ loading: false, error: "", success: "Expense submitted." });
      navigate("/expenses/history");
    } catch (error) {
      setStatus({ loading: false, error: "Unable to submit expense.", success: "" });
    }
  };
  return (
    <div className="page">
      <PageHeader
        title="Add expense"
        subtitle="Capture receipts and submit with the right policy context."
        actions={
          <button className="button button--ghost" type="button">
            Save draft
          </button>
        }
      />
      <div className="grid grid--two">
        <div className="card">
          <h3>Expense details</h3>
          <form className="form" onSubmit={handleSubmit}>
            <div className="field">
              <label htmlFor="vendor">Vendor</label>
              <input
                id="vendor"
                name="merchant"
                type="text"
                placeholder="Ex: Delta Airlines"
                value={form.merchant}
                onChange={handleChange}
                required
              />
            </div>
            <div className="field">
              <label htmlFor="amount">Amount</label>
              <input
                id="amount"
                name="amount"
                type="number"
                step="0.01"
                placeholder="$0.00"
                value={form.amount}
                onChange={handleChange}
                required
              />
            </div>
            <div className="field">
              <label htmlFor="date">Expense date</label>
              <input
                id="date"
                name="expense_date"
                type="date"
                value={form.expense_date}
                onChange={handleChange}
                required
              />
            </div>
            <div className="field">
              <label htmlFor="category">Category</label>
              <select
                id="category"
                name="category"
                value={form.category}
                onChange={handleChange}
                required
              >
                <option value="">Select category</option>
                {categories.map((category) => (
                  <option key={category.id} value={category.id}>
                    {category.name}
                  </option>
                ))}
              </select>
            </div>
            <div className="field">
              <label htmlFor="payment_method">Payment method</label>
              <select
                id="payment_method"
                name="payment_method"
                value={form.payment_method}
                onChange={handleChange}
              >
                <option value="credit_card">Credit card</option>
                <option value="debit_card">Debit card</option>
                <option value="cash">Cash</option>
                <option value="bank_transfer">Bank transfer</option>
                <option value="upi">UPI</option>
              </select>
            </div>
            <div className="field">
              <label htmlFor="notes">Notes</label>
              <textarea
                id="notes"
                name="description"
                placeholder="Add a short justification."
                value={form.description}
                onChange={handleChange}
                required
              />
            </div>
            {status.error ? <div className="alert">{status.error}</div> : null}
            <button className="button" type="submit">
              {status.loading ? "Submitting..." : "Submit expense"}
            </button>
          </form>
        </div>
        <div className="card">
          <h3>Spend trend (6 months)</h3>
          <div className="chart">
            <Line
              data={{
                labels: monthlyTrend.labels,
                datasets: [
                  {
                    label: "Monthly spend",
                    data: monthlyTrend.data,
                    borderColor: "#db7c2d",
                    backgroundColor: "rgba(219, 124, 45, 0.2)",
                    tension: 0.35,
                    pointRadius: 4,
                  },
                ],
              }}
              options={{
                responsive: true,
                plugins: { legend: { display: false } },
                scales: { y: { grid: { color: "rgba(0,0,0,0.05)" } } },
              }}
            />
          </div>
          <p className="stat-card__label">
            Current month: {formatCurrency(monthlyTrend.latest)}
          </p>
        </div>
      </div>
      <div className="card">
        <h3>Receipt + policy preview</h3>
        <div className="field">
          <label htmlFor="receipt">Upload receipt</label>
          <input id="receipt" name="receipt_file" type="file" onChange={handleFileChange} />
        </div>
        <div className="list">
          <div className="list-item">
            <div>
              <strong>Policy match</strong>
              <div className="stat-card__label">Travel policy v3.2</div>
            </div>
            <span className="chip">Aligned</span>
          </div>
          <div className="list-item">
            <div>
              <strong>Manager review</strong>
              <div className="stat-card__label">Auto-route to J. Lee</div>
            </div>
            <span className="chip">2 hrs</span>
          </div>
          <div className="list-item">
            <div>
              <strong>Receipt check</strong>
              <div className="stat-card__label">OCR pending</div>
            </div>
            <span className="chip">Queued</span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AddExpense;
